"""
mkt-context: Psalms 28-33
Chapters: 28-33 (89 verses)
Run: python3 scripts/zc-context-psalms-28-33.py

Key context decisions:
- Psalm 29: ANE/Ugaritic storm-god Baal parallel demythologized
- Psalm 30: Temple dedication / Hanukkah proto-type (2 Macc 1:9)
- Psalm 31: Into your hands (v5) dying formula / Jesus citation (Luke 23:46)
- Psalm 32: Three Hebrew forgiveness terms; one of 7 penitential psalms
- Psalm 33: 22 verses = aleph-bet count; creation-by-word polemic vs. ANE cosmogonies
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"28": {"1": "<p><b>Ps 28 superscription: 'A Psalm of David.'</b> The psalm is a personal lament transitioning to communal thanksgiving in vv6-9. The shift from individual petition (vv1-5) to communal blessing (vv8-9) suggests liturgical use at the Jerusalem sanctuary. David functions as representative of the whole people before YHWH.</p><p><b>'My Rock' (tzuri)</b> — the epithet <i>sur</i> (rock/crag) is the Mosaic appellative for YHWH developed in Deut 32 (the Song of Moses): 'The Rock — his work is perfect' (Deut 32:4). The rock imagery evokes the Sinai landscape and Mosaic covenant tradition. 'If you are silent I become like those who go down to the pit' — the fear is not merely death but divine abandonment, which in ANE thought meant losing access to the deity's protective power.</p>", "2": "<p><b>'Lifting hands toward your Most Holy Place' (el-devir qodshecha)</b> — <i>devir</i> is the inner sanctuary, the Holy of Holies, where the ark of the covenant resided. Prayer directed toward the <i>devir</i> represents the belief that YHWH's presence was specially localized there — a theology developed in 1 Kgs 8 (Solomon's temple dedication prayer). Before the temple was built, prayer may have been directed toward the Tent of Meeting. The gesture of lifted hands (<i>nisheat chapai</i>) is attested in Mesopotamian and Egyptian prayer postures: arms raised, palms up, in supplication before the deity. Ps 141:2 also connects lifted hands to incense offering — the bodily posture is a form of sacrifice.</p>", "3": "<p><b>'Who speak peace to their neighbors while plotting evil in their hearts'</b> — the social context is the royal court where political alliances were sealed with covenantal language of <i>shalom</i> (peace/wholeness) while treachery operated beneath. The ANE treaty tradition used <i>shalom</i> vocabulary to ratify suzerain-vassal relationships; speaking peace falsely was therefore a covenant violation. This pattern is reflected in Absalom's conspiracy (2 Sam 15) and the political intrigues surrounding David. The legal category of false witness (<i>ed shaqer</i>) was a specific covenant-court crime.</p>", "4": "<p><b>'Give them according to their work'</b> — the lex talionis principle (retributive justice in exact proportion) underpins the petition. In the ANE, divine retribution was understood as the deity enforcing the cosmic moral order. The plea that the wicked experience what they intended for others is rooted in Deuteronomic covenant theology: blessings for obedience, curses for betrayal (Deut 27-28). The petition is not mere vengeance but an appeal for YHWH to be the cosmic enforcer of covenant justice.</p>", "5": "<p><b>'Because they do not understand the works of the LORD'</b> — the theological diagnosis of wickedness is moral blindness to divine governance. In wisdom tradition (Prov 1:7; Ps 14:1), failure to acknowledge YHWH is the root of ethical disorder. The works of YHWH (<i>maasot YHWH</i>) in Psalmic theology are both the works of creation (Ps 8) and the works of history (Ps 77:11; 78:7). To be blind to these is to be structurally disoriented. The consequence — 'he will tear them down and not build them up' — echoes Jeremiah's call to 'tear down and build up' (Jer 1:10): destruction is the divine response to covenant breach.</p>", "6": "<p><b>'Blessed be the LORD, for he has heard the voice of my pleas'</b> — the pivot of the psalm: a sudden shift to praise in the perfect tense. This 'praise in advance' or 'certainty of hearing' is a characteristic form of Hebrew lament psalmody — the petitioner becomes so confident of divine response that the tone shifts from petition to thanksgiving before the answer arrives. This reflects the liturgical structure of the sanctuary: lament was offered and then priestly assurance of hearing may have been given (an <i>Heilsorakel</i>, salvation oracle), which the worshiper received as the answer.</p>", "7": "<p><b>'My heart trusts in him and I am helped'</b> — <i>batach</i> (trust/rely on) is the covenant-confidence vocabulary, contrasted with trusting in human military power (Ps 20:7; Isa 31:1). The movement from petition to confidence to praise follows the standard lament-psalm trajectory. 'My heart leaps for joy' — the physical location of emotion in the <i>lev</i> (heart/mind): ANE anthropology located reasoning, emotion, and will all in the heart-organ.</p>", "8": "<p><b>'The LORD is the strength of his people; he is the saving refuge of his anointed'</b> — <i>mashiach</i> (his anointed) here likely refers to the Davidic king as YHWH's covenant representative. The theology of the anointed king as the conduit of divine strength for the nation is developed in the Davidic covenant texts (2 Sam 7; Ps 2; 89). The king is <i>ma'oz</i> (strong fortress) for the people not through personal power but as the channel of YHWH's protection.</p>", "9": "<p><b>'Save your people and bless your inheritance; shepherd them and carry them forever'</b> — the psalm closes with communal prayer on behalf of all Israel, YHWH's <i>nachalah</i> (inheritance/estate). Israel as YHWH's inheritance is Deuteronomic theology (Deut 4:20; 9:29): the nation is YHWH's personal property, as land is a family's inheritance. 'Shepherd them' — the royal shepherd metaphor: kings in the ANE were regularly called shepherds of their people (Hammurabi's law code prologue; the Mesopotamian royal ideal). YHWH as shepherd of Israel reframes the royal function as divine rather than human.</p>"}, "29": {"1": "<p><b>Ps 29 and the Ugaritic Baal Cycle.</b> This psalm is widely recognized as the most deeply ANE-influenced in the Psalter. Its closest parallels are in Ugaritic Baal epic texts from Ras Shamra (14th-13th c. BC), which celebrate Baal-Hadad's storm victory over the sea god Yam. The sevenfold repetition of 'the voice of the LORD' (<i>qol YHWH</i>) echoes Baal's 'voice' (Baal's thunder = his war-shout). The psalm functions polemically: YHWH controls what Baal claimed.</p><p><b>'O heavenly beings' (bene elim)</b> — literally 'sons of gods/divine beings,' the divine council of the ANE cosmos. In Ugaritic texts, El's council (the sons of El) are the assembled divine beings. Ps 82 depicts YHWH judging this divine council. The call for the divine beings to glorify YHWH asserts his supremacy within the cosmic court.</p>", "2": "<p><b>'Worship the LORD in the splendor of his holiness'</b> — <i>hadar qodsho</i> (the splendor/glory of his holiness). ANE gods were worshiped with elaborate cultic splendor: garments, processions, music, and material glory. The psalm calls the divine beings to worship YHWH with the full display of divine honor that ANE court theology expected of vassal-deities before the great king. <i>Hodot le-shem</i> (give to the name) — the divine name in the ANE was not merely a label but the seat of the deity's identity and power: to glorify the name is to acknowledge the deity's full power.</p>", "3": "<p><b>'The voice of the LORD is over the waters'</b> — the sevenfold <i>qol YHWH</i> (vv3-9) is the theological heart of the psalm. In the Baal Cycle, Baal's voice is his thunder, his weapon in cosmic battle. Ps 29 appropriates this storm-theology and attributes it entirely to YHWH. 'Over the waters' — the cosmic waters (<i>mayim rabbim</i>, mighty waters) were a primary symbol of chaos in both Canaanite and Mesopotamian cosmology. YHWH's voice commanding the waters recalls Gen 1 and the Exodus sea-splitting. 'The God of glory' (<i>el ha-kavod</i>) — the only occurrence of this title in the Psalter.</p>", "4": "<p><b>'The voice of the LORD is powerful; the voice of the LORD is majestic'</b> — the repetition of <i>qol YHWH</i> without an accompanying action creates a sonic crescendo. Ugaritic poetry uses the same anaphoric repetition for Baal's storm. In Hebrew poetry, sevenfold repetition is associated with completeness: the seven-day creation, the sevenfold sprinkling of blood in priestly ritual. Seven utterances of <i>qol YHWH</i> implies YHWH's voice pervades all seven zones of the cosmos.</p>", "5": "<p><b>'The voice of the LORD breaks the cedars of Lebanon'</b> — Lebanon's cedars were the most famous and sacred trees in the ANE: the Baal Cycle describes Baal's palace built from Lebanese cedar; Mesopotamian epics feature the Cedar Forest as the dwelling of gods and monsters. To break the cedars of Lebanon is to demonstrate power over the most sacred natural symbol of the Canaanite divine world. Lebanon was Baal's territory, and YHWH's voice shatters it.</p>", "6": "<p><b>'He makes Lebanon skip like a calf, and Sirion like a young wild ox'</b> — Sirion is the Phoenician/Sidonian name for Mount Hermon (Deut 3:9), the sacred peak of the Canaanite divine assembly. Hermon/Sirion was associated with the oath sworn by the Watchers in 1 Enoch 6, suggesting its long-standing significance as a supernatural site. YHWH's storm-voice makes these sacred mountains dance — the divine council's residence trembles before him. The calf/wild ox imagery may also echo the bull iconography of Baal and El, which Israel controversially adopted (the golden calves of Exod 32; 1 Kgs 12:28).</p>", "7": "<p><b>'The voice of the LORD strikes with flashes of lightning'</b> — lightning as the divine weapon is pervasive in ANE storm-god theology: Baal wields the lightning bolt, as does the Mesopotamian storm-god Adad/Hadad. Zeus in Greek tradition carries the thunderbolt. Ps 29 does not deny the storm-phenomena but asserts that the one wielding the lightning is YHWH, not Baal. The Exodus tradition also uses storm-theophany (Exod 19 — the Sinai thunderstorm) to establish YHWH's identity as the true cosmic storm-lord.</p>", "8": "<p><b>'The voice of the LORD shakes the wilderness; the LORD shakes the wilderness of Kadesh'</b> — Kadesh-Barnea is the desert wilderness at the southern border of Canaan, the site of Israel's long encampment during the wilderness wandering. The geography moves from north (Lebanon, Hermon) to south (Kadesh wilderness): YHWH's storm-voice covers the entire land. The wilderness was both the zone of divine encounter (the Sinai revelation) and the zone of divine testing; its shaking signals YHWH's sovereign reach over the entire Exodus route.</p>", "9": "<p><b>'The voice of the LORD makes the deer give birth and strips the forests bare'</b> — the <i>ayalot</i> (deer/does) image: the pain of labor induced by divine storm. ANE birth texts associate violent natural events with the timing of labor. 'In his temple all cry Glory!' — the heavenly court acclaims YHWH's storm-victory: the divine council responds to the theophany with a shout of <i>kavod</i>. This mirrors the pattern of Isa 6 where the seraphim call 'holy, holy, holy' as YHWH appears in the temple.</p>", "10": "<p><b>'The LORD sits enthroned over the flood; the LORD sits enthroned as King forever'</b> — <i>mabul</i> (flood) is the rare technical term for Noah's flood (the only other uses are Gen 6-11). By using the flood-term, the psalm places YHWH's eternal kingship in the context of his cosmic victory over the waters of chaos: as he subdued the waters of the flood, so he reigns over all subsequent storms. The Babylonian Creation Epic (Enuma Elish) similarly celebrates Marduk's kingship following his victory over the sea-goddess Tiamat.</p>", "11": "<p><b>'The LORD gives strength to his people; the LORD blesses his people with peace'</b> — the storm theophany closes not with destruction but with <i>shalom</i>: the cosmic storm that threatens is channeled into blessing for the covenant community. This is the psalm's pastoral turn: the terrifying power celebrated in vv3-10 becomes protective strength and peace for Israel. YHWH's storm-power is not random cosmic violence (Baal's storms) but directed covenant protection.</p>"}, "30": {"1": "<p><b>Superscription: 'A Song for the Dedication of the Temple' (chanukkat ha-bayit)</b> — <i>chanukkah</i> means dedication/consecration, making this the proto-text of the Hanukkah festival (1 Macc 4:59; 2 Macc 1:9 links the rededication of the Maccabean temple to the original dedication). The individual lament-to-praise structure made the psalm suitable for the dedication context: personal rescue parallels the sanctuary's restoration after defilement. 'Of David' in the superscription is unusual given David did not build the temple — it may indicate Davidic authorship repurposed for a later dedication event.</p><p><b>'You have lifted me up' (dillitani)</b> — <i>dalah</i> (to draw up, as from a well) — the rescue metaphor is hydraulic: being pulled up out of the pit (the underworld, Sheol). The temple dedication context invites reading this as both individual recovery from illness and corporate recovery from national crisis.</p>", "2": "<p><b>'I cried to you for help and you healed me'</b> — the explicit healing language (<i>rapha</i>) suggests the psalm's original context was recovery from serious illness. In the ANE, illness and divine punishment were closely linked: disease was the deity's arrow (cf. Ps 38:2; Job 6:4; Baal's seven arrows of disease). The sick person had typically been 'abandoned' by their protective deity, and recovery was restoration of the divine-human relationship. Healing therefore required both medical treatment and religious ritual (offering, lament psalm).</p>", "3": "<p><b>'You brought my soul up from the realm of the dead; you restored my life from among those who descend to the pit'</b> — <i>Sheol</i> and <i>bor</i> (pit) are the two standard Hebrew terms for the underworld. ANE underworld theology (Mesopotamian Kur/Aralu, Canaanite Mot's realm) depicted it as a place of dust, darkness, and the weak shadows of the dead. The psalmist experienced illness as descent into Sheol's territory; recovery is literal resurrection from that borderland. This makes the psalm structurally a 'resurrection narrative' — the individual death-and-return experience that later provides typological language for Christ's resurrection.</p>", "4": "<p><b>'Sing praise to the LORD, you his faithful ones (chasidim)'</b> — the <i>chasidim</i> (plural of <i>chasid</i>) are the covenant-loyal community, those who practice <i>chesed</i> (covenant faithfulness). The term appears frequently in the Psalter as a self-designation of the devout community (Ps 4:3; 12:1; 16:10; 31:23; 37:28). The invitation to communal praise follows the ANE pattern of the recovered worshiper holding a thanksgiving feast and inviting the community to participate — the healed person's story becomes communal praise.</p>", "5": "<p><b>'His anger is for a moment; his favor is for a lifetime. Weeping may tarry for the night, but joy comes in the morning'</b> — the contrast of divine wrath (brief) and divine favor (a lifetime) is the psalm's theological thesis. ANE lament traditions often focused on the prolonged anger of the gods and the uncertainty of restoration; Ps 30 insists on YHWH's anger as limited and his <i>chayim</i> (life/favor) as permanent. The night/morning contrast was liturgically significant: the temple may have hosted vigils where lament was offered at night and praise in the morning (Ps 5:3; 59:16).</p>", "6": "<p><b>'In my prosperity I said, I shall never be moved'</b> — the retrospective confession of the prosperity illusion. ANE wisdom texts (Proverbs, Egyptian Instruction texts) warn against the arrogance of success: Ptahhotep's Maxims, the Instruction of Amenemope, and Israelite wisdom all diagnose prosperity-pride as the root of disaster. The psalmist's 'I shall not be moved' (<i>bal-emot</i>) echoes the language of the just person in Ps 1:3 and 15:5 — but here it is the arrogance of self-sufficiency rather than the confidence of trust.</p>", "7": "<p><b>'By your favor, O LORD, you made my mountain stand strong; you hid your face and I was terrified'</b> — YHWH's 'face-hiding' (<i>hisatarta panecha</i>) is one of the most significant theological concepts of the Psalter. In ANE patron-deity relationships, the god's 'face' (presence) was the source of all blessing; the hidden face meant withdrawal of protection, leaving the person exposed to disaster. The mountain imagery (<i>har</i>) may allude to the temple mount as YHWH's dwelling, or to the individual's secure situation. Strength comes from divine favor, not personal achievement.</p>", "8": "<p><b>'To you, O LORD, I called; to the LORD I pleaded for mercy'</b> — the account of the prayer offered during the crisis. The lament psalm was the standard liturgical form for such prayer: specific ritual texts were used at the sanctuary when approaching YHWH in distress. The psalmist's prayer in vv9-10 is a negotiation argument — appealing to YHWH's interests in maintaining the psalmist's life.</p>", "9": "<p><b>'What profit is there in my death, in my going down to the pit? Will the dust praise you? Will it declare your faithfulness?'</b> — the argument from divine self-interest: YHWH benefits from keeping the psalmist alive because the dead cannot praise him. This remarkable pragmatic argument assumes the Psalter's anthropology that the dead in Sheol do not have full relationship with YHWH (Ps 6:5; 88:10-12; 115:17). The argument is later answered in Isa 26:19 (resurrection) and definitively in the NT resurrection.</p>", "10": "<p><b>'Hear, O LORD, and be merciful to me; O LORD, be my helper'</b> — the three divine names/titles in this verse create an intensified plea: YHWH (covenant name) + <i>chonneni</i> (show grace, appeal to his nature) + YHWH (again) + <i>ezer</i> (helper, the Eden-word: Gen 2:18, 'ezer suitable for him'). The threefold address is a liturgical intensification pattern common in lament psalms.</p>", "11": "<p><b>'You have turned my mourning into dancing; you have removed my sackcloth and clothed me with joy'</b> — <i>saq</i> (sackcloth, goat-hair cloth) was worn as a physical enactment of mourning and petition — the rough texture signaled distress to both humans and the deity. Removing sackcloth was the physical cessation of mourning. Dancing (<i>machol</i>) was a liturgical practice at the sanctuary (Ps 149:3; 150:4; Jer 31:13). The clothing imagery (removing sackcloth, being clothed with joy) is a vestment metaphor: divine rescue changes the worshiper's liturgical garment.</p>", "12": "<p><b>'That my glory may sing your praise and not be silent. O LORD my God, I will give thanks to you forever'</b> — <i>kavodi</i> (my glory) — possibly the liver/soul as seat of honor, or the psalmist's reputation in the community. The restored person's public praise is the completion of the rescue: honor is restored through public thanksgiving. The vow 'I will give thanks forever' concludes what likely was a thanksgiving offering ceremony at the temple, where the recovered person brought a <i>todah</i> (thanksgiving) sacrifice and recited the psalm publicly (Ps 22:25; 116:14).</p>"}, "31": {"1": "<p><b>Ps 31 is one of the most liturgically influential laments in the Psalter.</b> Its influence on NT passion narratives is extensive (v5 cited by dying Jesus; echoes in Jeremiah's confessions). The superscription 'For the director of music' (<i>la-menatzeach</i>) indicates professional temple performance. 'Let me never be put to shame' (<i>al-evoshu leolam</i>) — <i>bosh</i> (shame) was the public social experience of failure and loss of honor. In an honor-shame culture, public shame represented real social destruction: the shamed person lost standing, relationships, and potentially livelihood.</p>", "2": "<p><b>'Turn your ear to me; quickly rescue me. Be my rock of refuge, a strong fortress'</b> — the request for speed (<i>mehera hatzileni</i>) reflects the urgency of the crisis. 'Rock of refuge' (<i>tzur maoz</i>) and 'strong fortress' (<i>bet metsudat</i>) are military metaphors from siege warfare: the high rock-fortress (such as Masada, or the Judean hill fortresses) provided safety that flat terrain did not. YHWH as the ultimate fortress is a metaphor for the futility of every human military defense against divine protection.</p>", "3": "<p><b>'For you are my rock and my fortress; lead me and guide me for your name's sake'</b> — the petition 'for your name's sake' (<i>lemaan shimecha</i>) is a covenant argument: YHWH's name and reputation are at stake in his treatment of his servant. If YHWH abandons the one who trusts him, YHWH's character is impugned before the nations (cf. Ezek 36:22: YHWH acts 'for the sake of his holy name'). This rhetorical strategy — appealing to divine self-interest — is common in Psalter and prophetic intercession.</p>", "4": "<p><b>'Lead me out of the net they have hidden for me, for you are my refuge'</b> — <i>reshet</i> (net) — the hunting net as enemy trap. ANE hunting imagery pervades Psalter lament psalms: the psalmist as prey of hunters, the enemies as hunters who lay nets, pits, and snares. This reflects both literal practices of ancient hunting (nets were used to catch animals) and a metaphorical framework for understanding social and political persecution.</p>", "5": "<p><b>'Into your hand I commit my spirit; you have redeemed me, O LORD, faithful God'</b> — <i>beyadechah apqid ruchi</i> — the dying-person formula: entrusting the life-breath to divine keeping. This was likely a standard bedtime prayer or deathbed commendation formula in Second Temple Judaism. Jesus cites it as his last words in Luke 23:46, giving it its fullest weight. <i>Paditha</i> (you have redeemed, Qal perfect) — the redemption here is past-tense assurance, an expression of certainty of divine response typical of lament psalms. <i>El emet</i> (faithful God) — the God of <i>emet</i> (truthfulness, reliability) keeps his covenant promises.</p>", "6": "<p><b>'I hate those who pay regard to worthless idols, but I trust in the LORD'</b> — <i>havle shav</i> (worthless/vain idols, literally 'vapors of emptiness') — the polemic against idol-worship. The contrast between trusting in <i>havle shav</i> and trusting in YHWH is the fundamental religious binary of the Psalter. ANE religion offered a spectrum of patron deities one could appeal to; Psalmic theology insists on exclusive YHWH-loyalty. The word <i>havel</i> will become Qohelet's signature term in Ecclesiastes.</p>", "7": "<p><b>'I will rejoice and be glad in your steadfast love, for you have seen my affliction; you have known the distress of my soul'</b> — <i>chesed</i> (steadfast love) + divine knowing of human suffering: the combination asserts that YHWH is both loving and attentive. In ANE religion, a distant or indifferent deity was a real possibility; petitions often began with rousing the god from sleep or inattention (cf. the Baal-mockery of Elijah in 1 Kgs 18:27). Ps 31 assumes YHWH's attentiveness: he has 'seen' (<i>raita</i>) the affliction and 'known' (<i>yadacta</i>) the distress — the intimate knowing of Gen 4:1 and Exod 3:7.</p>", "8": "<p><b>'You have not delivered me into the hand of the enemy; you have set my feet in a broad place'</b> — <i>bammerchav</i> (in the broad place) — the spatial metaphor of rescue as spaciousness (cf. Ps 18:19; 118:5). ANE cities were cramped and enclosed; the open plain was associated with freedom and safety. The enemy's hand represents capture and constraint; the broad place represents delivered freedom.</p>", "9": "<p><b>'Be gracious to me, O LORD, for I am in distress; my eye is wasted from grief; my soul and my body also'</b> — the physical-psychological-spiritual triple distress: eye, soul (<i>nephesh</i>), body (<i>beten</i>, literally 'belly') are all affected. ANE lament texts regularly describe illness in terms of multiple body-parts being afflicted simultaneously: the Babylonian Ludlul Bel Nemeqi ('I will praise the Lord of Wisdom') similarly catalogs multi-member suffering.</p>", "10": "<p><b>'For my life is spent with sorrow, and my years with sighing; my strength fails because of my iniquity, and my bones waste away'</b> — <i>avoni</i> (my iniquity) — a striking admission that the psalmist connects suffering to sin. The body-as-moral-barometer was common in ANE anthropology: illness was divine punishment for covenant violation. This is the framework that Job's friends apply (and which the book of Job then critiques). The psalmist does not debate the connection but confesses it as grounds for mercy rather than justice.</p>", "11": "<p><b>'Because of all my adversaries I have become a reproach, especially to my neighbors, and an object of dread to my acquaintances'</b> — the social dimensions of the crisis: neighbors distance themselves, acquaintances flee. In ANE society, the sick and accused were socially dangerous — associating with them risked ritual contamination or political guilt-by-association. The abandoned person becomes an object of shame (<i>cherpah</i>) and horror (<i>pachad</i>): two registers of social disaster.</p>", "12": "<p><b>'I have been forgotten like one who is dead; I have become like a broken vessel'</b> — the double death-metaphor: forgotten like the dead and shattered like a useless pot. In ANE funerary practice, broken pottery was scattered over graves and at the boundary of the underworld — the broken vessel was an image of death itself. The social memory of the community was the closest thing to 'life after death' in pre-resurrection Hebrew anthropology: to be 'forgotten like the dead' was the ultimate social erasure.</p>", "13": "<p><b>'For I hear the whispering of many — terror on every side'</b> — <i>magor missaviv</i> (terror on every side/all around) — this exact phrase appears in Jeremiah's confessions as a taunt applied to him (Jer 20:3-4, 10): Jeremiah himself uses it sardonically and then applies it to himself. The phrase became a standard description of the experience of the persecuted prophet. The whispering (<i>dibbat rabbim</i>) is the slander that travels quietly through social networks, destroying reputation.</p>", "14": "<p><b>'But I trust in you, O LORD; I say, You are my God'</b> — the pivot of the psalm: the declaration of trust in the middle of the crisis. 'You are my God' is the covenant declaration — the personal appropriation of the covenant formula ('I will be your God and you will be my people'). In the midst of social abandonment and terror, the psalmist claims the covenant relationship as the counter-reality.</p>", "15": "<p><b>'My times are in your hand; rescue me from the hand of my enemies and from my persecutors'</b> — <i>ittotai beyadechah</i> (my times/seasons are in your hand) — a profound statement of divine providence over the calendar of the psalmist's life. The 'times' include both the difficult moments and the moments of rescue. The persecutors think they control the timing of the psalmist's fate; the psalmist claims YHWH controls it.</p>", "16": "<p><b>'Make your face shine on your servant; save me in your steadfast love'</b> — the Aaronic blessing language (Num 6:25-26) becomes personal petition: 'make your face shine' (<i>haer panecha</i>) is precisely the priestly blessing formula. The psalmist asks to receive what priests pronounced — the shining divine face as the experience of grace. <i>Chesedechah</i> (your steadfast love) — salvation through covenant love, not merit.</p>", "17": "<p><b>'O LORD, let me not be put to shame, for I call upon you; let the wicked be put to shame; let them go silently to Sheol'</b> — the reversal of shame: the psalmist asks that the shame intended for him be transferred to the wicked. 'Silently to Sheol' — the silence of Sheol (<i>dumah</i>) contrasts with the noise of the slanderers' whispering (v13). The judgment is poetic: those who used their mouths to destroy will be silenced in death.</p>", "18": "<p><b>'Let the lying lips be mute, which speak insolently against the righteous with pride and contempt'</b> — <i>siphte shaqer</i> (lying lips) — the legal category of false witness (<i>ed shaqer</i>) is implied. In the covenant court, false witnesses who deliberately harmed the innocent were to receive the punishment intended for the accused (Deut 19:16-19). The psalmist's prayer for silence of lying lips invokes this legal principle.</p>", "19": "<p><b>'Oh, how abundant is your goodness, which you have stored up for those who fear you'</b> — <i>tzafanta</i> (stored up) — the divine goodness is not spent but reserved and accumulated for the fearers. ANE royal storehouses (grain, oil, valuables) provided for the king's household and dependents; YHWH's goodness functions as a divine storehouse for those who are covenant-loyal. The stored goodness will be publicly displayed, vindicating the fearers before the watching community.</p>", "20": "<p><b>'In the shelter of your presence you hide them from the plots of men; you store them in your shelter from the strife of tongues'</b> — <i>beseter panechah</i> (in the shelter of your face/presence) and <i>sukkah</i> (booth/shelter) — two shelter metaphors for divine protection. The divine face (<i>panim</i>) as shelter creates a protective zone around the covenant-loyal. The Feast of Tabernacles (<i>Sukkot</i>) enacted this theology: the <i>sukkah</i> booth was a reminder of divine shelter in the wilderness. 'Strife of tongues' (<i>riv leshonot</i>) — legal/courtroom conflict and slander.</p>", "21": "<p><b>'Blessed be the LORD, for he has wondrously shown his steadfast love to me when I was in a besieged city'</b> — <i>ber ir matzor</i> (a besieged city) — the military metaphor for the crisis is now explicit. ANE siege warfare was the most terrifying military scenario: the city's food supply was cut off, disease spread, and the population faced starvation or slaughter. YHWH's <i>chesed</i> is 'wondrous' (<i>hiphli</i> = miraculous, extraordinary) precisely because it operated under conditions that seemed impossible for rescue.</p>", "22": "<p><b>'I had said in my alarm, I am cut off from your sight. But you heard the voice of my pleas for mercy'</b> — the past-tense report of the crisis-moment conviction that YHWH had severed the relationship. This is the experience of divine abandonment that v1 prays against: the psalmist believed it had happened, then discovered it had not. The gap between the felt experience of divine absence and the actuality of divine presence is a central dynamic of lament psalmody.</p>", "23": "<p><b>'Love the LORD, all you his saints (chasidim)! The LORD preserves the faithful but abundantly repays the one who acts in pride'</b> — the communal exhortation following personal rescue: the individual's experience grounds corporate instruction. 'Preserves the faithful' (<i>notzer emunim</i>) — <i>emun</i> (faithful, from <i>aman</i>) — the covenant-reliable person is protected by YHWH. 'Acts in pride' (<i>gaavah</i>, haughtiness) — the contrast with <i>anav</i> (humble/afflicted) throughout the Psalter: pride is the disposition of those who do not need God.</p>", "24": "<p><b>'Be strong and let your heart take courage, all you who wait for the LORD'</b> — the psalm closes with the same encouragement that closes Joshua 1 and Deut 31 ('be strong and courageous, <i>chizqu veyimatz libbekem</i>'). The Mosaic/Deuteronomic formula is applied to the situation of all who 'wait' (<i>meyachalim</i>) for YHWH — not just military warriors but all who exercise covenant patience. The psalm has moved from individual cry (v1) to communal strength-exhortation (v24): the rescue of one person becomes resource for the whole community.</p>"}, "32": {"1": "<p><b>Ps 32 superscription: 'A Maskil of David'</b> — <i>maskil</i> is a term of uncertain technical meaning (from <i>sakal</i>, to be wise/successful): possibly 'instructional psalm,' 'contemplative,' or a musical term. Ps 32 is classified as one of the Seven Penitential Psalms in Christian tradition (with Pss 6, 38, 51, 102, 130, 143), making it a primary text for sacramental confession from patristic times forward. Augustine reportedly had this psalm written on his bedroom wall.</p><p><b>Three Hebrew forgiveness terms in vv1-2:</b> (1) <i>nasa pesha</i> (lifted/carried away transgression) — <i>pesha</i> is willful breach of covenant; <i>nasa</i> (to lift, carry) — the bearing-away of guilt, the root of the scapegoat ritual (Lev 16:22). (2) <i>kesuy chata</i> (sin covered) — <i>chasah</i> (to cover) — concealing sin from divine view, used of the atonement lid (<i>kapporet</i>, mercy seat) on the ark. (3) <i>lo-yachshov avon</i> (not reckoning iniquity) — the forensic term: God does not enter the debt on the ledger. Paul cites v2 in Rom 4:7-8 as evidence of imputed righteousness.</p>", "2": "<p><b>'Blessed is the man to whom the LORD does not reckon iniquity, and in whose spirit there is no deceit'</b> — <i>lo-yachshov</i> (does not reckon/count) — the accounting metaphor: <i>chashav</i> (to reckon, calculate, plan) used of commercial ledgers. The forgiven person's account shows no debt. 'In whose spirit there is no deceit' (<i>ein rucho remiyyah</i>) — <i>remiyyah</i> (deceit, slackness) — the forgiven person is also honest: the blessing is not amnesty for continued deception but the relief of genuine confession and clean standing.</p>", "3": "<p><b>'When I kept silent about my sin, my bones wasted away through my constant groaning'</b> — the physical effects of unconfessed sin. ANE medical texts did not separate physical illness from spiritual/moral disorder — the body bore the consequences of covenant violation. 'Bones' (<i>atzamot</i>) as the structural framework of the person: when they waste, the whole person is in collapse. The 'constant groaning' (<i>beshagati kol-hayom</i>) — involuntary sounds of suffering that escape despite the silence about sin.</p>", "4": "<p><b>'For day and night your hand was heavy upon me; my strength was dried up as by the heat of summer'</b> — 'the heavy hand of YHWH' (<i>yad YHWH nichbedah alai</i>) — divine pressure as weight: the physical sense of being crushed. The image appears in Ezek 3:14; 1 Sam 5:6 (the heavy hand on the Philistines with the captured ark). The summer heat (<i>charbonei kayitz</i>) dries up moisture — the unconfessed-sin body has no internal resources left. Selah marks a liturgical pause, probably an instrumental interlude.</p>", "5": "<p><b>'I acknowledged my sin to you and I did not cover my iniquity; I said, I will confess my transgressions to the LORD, and you forgave the iniquity of my sin'</b> — the resolution: acknowledgment ends the hiding, and divine forgiveness follows immediately. 'You forgave' — the Hebrew is literally 'you lifted/carried (<i>nasa</i>) the iniquity of my sin' — the same bearing-away term as v1. The act of confession triggers the same forgiveness that the opening beatitude described.</p>", "6": "<p><b>'Therefore let everyone who is godly offer prayer to you at a time when you may be found'</b> — <i>let chesed</i> (one who is godly, lit. one who practices covenant-love) — the community is invited into the same prayer. 'At a time when you may be found' (<i>leet metzo</i>) — divine accessibility is not guaranteed: there are times when the door of prayer is particularly open. This urgency about the timing of prayer echoes Isa 55:6 ('seek the LORD while he may be found').</p>", "7": "<p><b>'You are a hiding place for me; you preserve me from trouble; you surround me with shouts of deliverance'</b> — <i>seter</i> (hiding place, shelter — the divine protective enclosure). The sanctuary itself was called a place of divine shelter (Ps 27:5; 31:20). 'Shouts of deliverance' (<i>rannei pallet</i>) surrounding the forgiven person — the joyful community-shout of rescue that answers the groaning of vv3-4. The liturgical movement: groaning → confession → prayer → divine shelter and rescue-shout.</p>", "8": "<p><b>'I will instruct you and teach you in the way you should go; I will counsel you with my eye upon you'</b> — the speaker shifts to YHWH (or possibly a priest/wisdom teacher). The wisdom-teacher role mirrors the relationship of Proverbs: the experienced teacher who has walked the path of confession and forgiveness now guides others. 'With my eye upon you' (<i>etsah alecha eini</i>) — attentive guidance, watching the path. This contrasts with the mule/horse of v9 who require bit and bridle because they do not look to their guide.</p>", "9": "<p><b>'Be not like a horse or a mule, without understanding, which must be curbed with bit and bridle, or it will not stay near you'</b> — the wisdom fable of the untamed animal requiring physical restraint. ANE wisdom literature (Proverbs, Amenemope) commonly uses animal analogies: the stubborn ox, the foolish animal that must be beaten into compliance. The human who requires divine 'bit and bridle' (crisis, suffering) rather than responsive wisdom is the fool of Prov 12:1. The confession of v5 is what the responsive person does; the unresponsive person requires the heavy hand of v4.</p>", "10": "<p><b>'Many are the sorrows of the wicked, but steadfast love surrounds the one who trusts in the LORD'</b> — the two circles: <i>makkot harbeh</i> (many strikes/sorrows) surrounding the wicked, and <i>chesed</i> (steadfast love) surrounding the trusting. The one who trusts (<i>ha-boteach</i>) is encircled by covenant love — the same <i>chesed</i> vocabulary that makes David's covenant (2 Sam 7:15) permanent. <i>Batach</i> (trust) is the behavioral posture that positions the person within the circle of <i>chesed</i>.</p>", "11": "<p><b>'Be glad in the LORD, and rejoice, O righteous, and shout for joy, all you upright in heart'</b> — the closing summons to communal praise, matching the opening beatitude (v1). The threefold command (be glad, rejoice, shout) encompasses the whole person: inner gladness, expressed rejoicing, and public shout. The <i>yishreh-lev</i> (upright in heart) of the closing verse echoes the 'no deceit in spirit' of v2: the community of the forgiven is the community of the inwardly honest, and their praise arises from the release of forgiveness.</p>"}, "33": {"1": "<p><b>Ps 33: 22 verses for 22 letters.</b> This anonymous hymn has exactly 22 verses — precisely the number of letters in the Hebrew alphabet. Unlike Pss 25, 34, 37, 111, 112, 119, 145, it is not formally an acrostic, but the 22-verse structure is almost certainly intentional: the praise of YHWH is comprehensive as the alphabet itself. The psalm has no superscription, unusual in Book I — possibly indicating very early use or that its creation-theology content was considered self-evident. 'Shout for joy in the LORD, you righteous' — the imperative form of communal summons (<i>ranenu</i>, ring out, shout).</p>", "2": "<p><b>'Praise the LORD with the lyre; make music with the ten-stringed harp'</b> — <i>kinor</i> (lyre) and <i>nevel asor</i> (ten-stringed harp) were the principal instruments of the Levitical temple orchestra. David was credited with organizing the Levitical musicians (1 Chr 25), and the lyre (<i>kinor</i>) was David's own instrument (1 Sam 16:16). Ps 33 assumes the Second Temple's institutional music program: worship was performed by professionals.</p>", "3": "<p><b>'Sing to him a new song (shir chadash); play with skill, shout for joy'</b> — <i>shir chadash</i> (new song) — the 'new song' phrase in the Psalter (Pss 40, 96, 98, 144, 149; Isa 42:10; Rev 5:9; 14:3) is a programmatic declaration that YHWH's acts in history are always generating fresh praise. The new song is not novelty for its own sake but the fresh doxological response to each new saving act. <i>Heitev naggen</i> (play skillfully) — musical excellence as a form of worship: ANE temple music required trained professionals.</p>", "4": "<p><b>'For the word of the LORD is upright, and all his work is done in faithfulness'</b> — the theological grounding of worship: <i>davar YHWH yashar</i> (the word of the LORD is straight/right) and <i>kol maasehhu beemunah</i> (all his work in faithfulness). The two grounds of praise: the divine word (revelation/promise) and the divine works (creation/history). Both are characterized by straightness (<i>yashar</i>) and reliability (<i>emunah</i>). Promise and fulfillment form the redemptive arc.</p>", "5": "<p><b>'He loves righteousness and justice; the earth is full of the steadfast love of the LORD'</b> — <i>tzedaqah umishpat</i> (righteousness and justice) are the twin pillars of the Davidic throne (Ps 89:14; Isa 9:7) and of divine governance (Ps 97:2). <i>Chesed YHWH malah haaretz</i> (the earth is full of the steadfast love of the LORD) — later echoed verbatim in Ps 119:64. The comprehensive reach of divine love is the theological premise for all that follows in the psalm.</p>", "6": "<p><b>'By the word of the LORD the heavens were made, and by the breath of his mouth all their host'</b> — <i>bidvar YHWH shamayim naasu</i> — creation by divine speech, echoing Gen 1 ('God said... and it was'). This is the Bible's most explicit creation-by-word statement outside Gen 1 itself. ANE cosmogonies (Enuma Elish) required combat for creation; Ps 33 asserts creation by word alone, requiring no resistance from pre-existing matter or rival deities. The Stoic concept of the divine Logos and John 1:1-3 both engage this tradition.</p>", "7": "<p><b>'He gathers the waters of the sea as a heap; he puts the deeps in storehouses'</b> — the creation image of the sea gathered like a pile (<i>kaned</i>, like a wineskin heap or a dam). God's control of the chaotic waters (Gen 1:9-10) is pictured as administrative storage: the waters are not eliminated but contained in divine storehouses (<i>otzarot</i>). The cosmic storehouses of wind, rain, snow, hail, and sea appear throughout the OT (Job 38:22; Jer 10:13; Ps 135:7). The Exodus Reed Sea event (Exod 15:8) echoes this creation imagery.</p>", "8": "<p><b>'Let all the earth fear the LORD; let all the inhabitants of the world stand in awe of him'</b> — the universalism of the summons: not just Israel but 'all the earth' (<i>kol haaretz</i>) and 'all the inhabitants of the world' (<i>kol yoshvei tevel</i>). The scope of the creation claim (vv6-7) generates a universal summons: if YHWH created everything, everything owes him reverential acknowledgment. This universalism undergirds the prophetic vision of all nations coming to YHWH (Isa 2:2-4; 45:22-23).</p>", "9": "<p><b>'For he spoke, and it came to be; he commanded, and it stood firm'</b> — the most concise expression of creation-by-word in Scripture: divine speech (amar, tzivvah) = being (wayehi, yaamad). No gap between divine intention and cosmic realization. This immediacy contrasts with ANE creation stories that require labor, struggle, or the work of craftsman-gods (the Aten hymn, Ptah's creation by thought, Marduk's careful construction). YHWH speaks and it is.</p>", "10": "<p><b>'The LORD brings the counsel of the nations to nothing; he frustrates the plans of the peoples'</b> — <i>YHWH hefir atzat goyim</i> — the sovereignty of YHWH over human political planning. ANE imperial ideology (Assyrian, Babylonian) was built on the idea that the empire's gods had decreed its expansion and that no human or divine resistance could prevail. Ps 33 directly counters this: YHWH nullifies the plans of the most powerful nations. The Babel narrative (Gen 11:1-9) is the paradigm case. Isaiah similarly mocks Assyria's plans (Isa 10:5-15).</p>", "11": "<p><b>'The counsel of the LORD stands forever, the plans of his heart to all generations'</b> — the contrast with v10: human counsel = frustrated; divine counsel = permanent. <i>Atzat YHWH leolam taamid</i> — the covenant word that stands forever is the theological foundation of Israel's hope through every imperial threat. Assyria's plans end, Babylon's plans end, Persia's plans end — but YHWH's plan for his people stands through every generation. Isa 14:24-27 makes the same argument about Assyria.</p>", "12": "<p><b>'Blessed is the nation whose God is the LORD, the people whom he has chosen as his heritage'</b> — <i>ashre ha-goy asher YHWH elohav</i> — the national beatitude. The <i>ashre</i> formula here is applied to a nation, not an individual: national blessedness is rooted in covenant relationship. <i>Ha-am bachar lenachalato</i> (the people he has chosen as his heritage) — Israel as YHWH's <i>nachalah</i> (inheritance/estate) is Deuteronomic theology (Deut 4:20; 9:29; 32:9).</p>", "13": "<p><b>'The LORD looks down from heaven; he sees all the children of man'</b> — the divine omniscience as witness: YHWH surveys all humanity from the heavenly throne. The watchtower metaphor (God seeing down from heaven) recurs in Gen 11:5; 18:21 (the Babel and Sodom stories); the pattern is that YHWH descends to investigate after observing from above. The divine surveillance is not merely monitoring but the exercise of providential governance.</p>", "14": "<p><b>'From where he sits enthroned he looks out on all the inhabitants of the earth'</b> — <i>mechon shivto</i> (from his established dwelling, the celestial throne). The heavenly temple as the locus of divine governance is consistent through the Psalter (Ps 11:4; 29:9; 103:19) and the prophets (Isa 6:1; 66:1). The enthronement of YHWH over the flood (Ps 29:10) and the enthronement at creation (Ps 93) provide the cosmological context for this oversight of all humanity.</p>", "15": "<p><b>'He who fashions the hearts of them all and observes all their deeds'</b> — <i>hayotzer yachad libbam</i> (who fashions/forms all their hearts together). The creator-God who formed the world by word also formed every human heart. The word <i>yotzer</i> (fashioner, potter) is the Gen 2:7 word: 'YHWH God formed (<i>vayyitzer</i>) the man from dust.' The God who formed humanity can therefore read humanity: he knows every person's deeds because he shaped the moral faculty that produced them.</p>", "16": "<p><b>'The king is not saved by his great army; a warrior is not delivered by his great strength'</b> — the anti-military polemic that runs throughout the Psalter: military might is not the decisive factor in battle (Ps 20:7; 46:9; 147:10). This was counter-cultural in the ANE, where military success was attributed to the patron deity's favor and the king's military prowess. The Deuteronomic prohibition on multiplying horses (Deut 17:16) is the legal expression of this theology.</p>", "17": "<p><b>'The war horse is a false hope for salvation, and by its great might it cannot rescue'</b> — <i>sheqer ha-sus liteshuah</i> (the horse is a lie for salvation) — the war horse as military technology (<i>sus</i> was the chariot horse; chariot warfare was the decisive military technology of the ANE). The claim that chariots and horses are 'false hope' is the same polemic Isaiah makes against Egyptian military alliance (Isa 31:1-3). YHWH's salvation operates independently of, and often against, military calculation.</p>", "18": "<p><b>'Behold, the eye of the LORD is on those who fear him, on those who hope in his steadfast love'</b> — <i>hinneh ein YHWH el-yereav</i> — the divine eye that watches all humanity (vv13-15) has a particular direction of care toward those who fear him. The universalism of divine surveillance and the particularism of covenant care are held together. The 'fearers' (<i>yereav</i>) and those who 'hope in his steadfast love' (<i>ha-mechalim lechasdo</i>) define the covenant community by their two defining postures: reverential trust and hope.</p>", "19": "<p><b>'That he may deliver their soul from death and keep them alive in famine'</b> — the specific content of covenant care: <i>naphesh</i> from <i>mavet</i> (death), life in <i>raav</i> (famine). Death and famine were the two great covenant curses (Deut 28:21-24 — plague and drought among the covenant judgments); YHWH's protection of the fearers is rescue from the very curses that fall on covenant violators. The Joseph narrative (Gen 41-50) is the paradigm case: Israel is kept alive in famine precisely through covenant faithfulness.</p>", "20": "<p><b>'Our soul waits for the LORD; he is our help and our shield'</b> — <i>naphshenu chikketah laYHWH</i> (our whole being waits for the LORD). The shift to first person plural ('our soul') signals the communal dimension: the congregation speaks together. <i>Ezer</i> (help — the Gen 2:18 word) and <i>magen</i> (shield — the Abrahamic covenant title: Gen 15:1) together define YHWH's protective function. Both are relational terms: YHWH as the one who helps from within relationship.</p>", "21": "<p><b>'For our heart is glad in him, because we trust in his holy name'</b> — <i>libbenu yismach bo</i> (our heart rejoices in him) — the communal heart as the locus of covenant joy. 'His holy name' (<i>shem qodsho</i>) — the divine name is holy because it carries the weight of divine character: to trust the name is to trust the character behind it. The name YHWH was revealed at Sinai (Exod 3:14-15; 6:2-3) as the pledge of covenant faithfulness: trusting the name means trusting the covenant history it encapsulates.</p>", "22": "<p><b>'Let your steadfast love, O LORD, be upon us, even as we hope in you'</b> — the psalm closes as a prayer: <i>yehi chasdecha YHWH aleinu</i> (let your <i>chesed</i> be upon us). The God who created by word, who frustrates nations, who watches from heaven, who cares for fearers — let that God's <i>chesed</i> rest specifically on the praying community. 'As we hope in you' (<i>kaasher yichalnu lach</i>) — the hope is both the condition and the ground: their hoping toward YHWH is the proper posture that receives the <i>chesed</i>.</p>"}}

if __name__ == '__main__':
    book = 'psalms'
    source = 'mkt-context'
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f'  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge')
